/**
 * The host coding agent's stable session id, or null when the agent doesn't
 * expose one. Used to scope per-agent local state (e.g. the active Studio
 * session handshake) so multiple agents sharing one worktree don't collide.
 *
 * Only STABLE per-session ids are returned: the value keys a cross-process
 * handshake, so a writer and a later reader (separate command invocations)
 * must resolve the same id throughout one agent session. Per-request ids are
 * deliberately excluded.
 *
 * - Claude Code: `CLAUDE_CODE_SESSION_ID` — documented, stable for the session
 *   lifetime (survives context compaction; reused on `--resume`/`--continue`;
 *   only `/branch` / `--fork-session` mints a new one).
 * - Codex: `CODEX_THREAD_ID` — the thread id Codex sets in the subprocess env;
 *   thread-scoped, so session-like. Not yet an officially documented session-id
 *   variable (openai/codex#8923 requests `CODEX_SESSION_ID`), but it is the most
 *   stable identifier Codex currently exposes.
 * - Cursor: none. Cursor exposes `CURSOR_AGENT` / `CURSOR_TRACE_ID` but no
 *   stable session id, and `CURSOR_TRACE_ID` is per-request, so it is NOT used.
 *   Cursor callers fall back to cwd-based scoping.
 */
export declare function getAgentSessionId(): string | null;
